class Solution(object):
    def lastNonEmptyString(self, s):
        from collections import Counter
        cnt = Counter(s)
        max_freq = max(cnt.values())
        last = {}
        for i, c in enumerate(s):
            if cnt[c] == max_freq:
                last[c] = i
        return ''.join(sorted(last.keys(), key=lambda c: last[c]))
